module sr_latch (  
    input wire S,  
    input wire R,  
    output reg obf_Q  
);  
    always @ (S, R) begin  
        if (S && ~R)  
            obf_Q <= 1; // Set  
        else if (~S && R)  
            obf_Q <= 0; // Reset  
        // If both S and R are low, retain the state (no change)  
        // If both S and R are high, maintain the previous state (indeterminate)  
    end  
endmodule
